<script setup>import {onMounted,ref} from 'vue';import {getAdminTradeIns} from '../api/tradeInApi';const list=ref([]),loading=ref(true),error=ref('');async function load(){loading.value=true;try{list.value=await getAdminTradeIns()}catch(e){error.value=e.message}finally{loading.value=false}}onMounted(load)</script>
<template><section class="admin-page"><div class="page-heading"><div><span class="eyebrow">TRADE-IN MANAGEMENT</span><h1>收購管理</h1><p>檢視估價申請、提供報價並管理收購進度。</p></div></div><p v-if="error" class="alert alert-error">{{error}}</p><div class="card table-card"><div v-if="loading" class="loading-state">正在載入收購申請…</div><div v-else-if="!list.length" class="empty-state"><h2>目前沒有收購申請</h2></div><div v-else class="table-scroll"><table><thead><tr><th>申請編號</th><th>會員</th><th>裝置</th><th>機況</th><th>期望價格</th><th>報價</th><th>狀態</th><th>操作</th></tr></thead><tbody><tr v-for="item in list" :key="item.id"><td><strong>{{item.tradeInNumber}}</strong></td><td>{{item.memberName}}</td><td>{{item.brand}} {{item.model}}<br><small>{{item.storageCapacity}}</small></td><td>{{item.appearanceCondition}}／{{item.functionCondition}}</td><td>{{item.expectedPrice?`NT$ ${Number(item.expectedPrice).toLocaleString()}`:'-'}}</td><td>{{item.quotedPrice?`NT$ ${Number(item.quotedPrice).toLocaleString()}`:'-'}}</td><td><span class="badge">{{item.status}}</span></td><td><RouterLink class="button button-secondary button-small" :to="`/admin/trade-ins/${item.id}`">管理</RouterLink></td></tr></tbody></table></div></div></section></template>
